-- =============================================================================
-- UNIFIED THEME SYSTEM — palette-driven
-- =============================================================================
-- Palettes are defined below. current-theme.lua (auto-generated by
-- scripts/switch-theme.sh) records which palette is active. Cycle palettes
-- from inside nvim with <leader>xt; that shells out to switch-theme so all
-- tools (tmux, ghostty, starship, fish) stay in sync.

local M = {}

