-- =============================================================================
-- HIGHLIGHTS
-- =============================================================================

local function apply_highlights(p)
  local hl = function(group, opts) vim.api.nvim_set_hl(0, group, opts) end

  -- Palettes that predate the type/constant split fall back to purple.
  local type_color = p.type_color or p.purple

  -- Core UI
  hl('Normal', { bg = p.bg, fg = p.fg })
  hl('NormalNC', { bg = p.bg, fg = p.fg })   -- non-current window: stay on palette bg
  hl('NormalFloat', { bg = p.surface, fg = p.fg })
  hl('Pmenu', { bg = p.surface, fg = p.fg })
  hl('PmenuSel', { bg = p.highlight, fg = p.fg, bold = true })
  hl('Visual', { bg = p.highlight })
  hl('CursorLine', { bg = p.cursor_line })
  hl('CursorLineNr', { fg = p.cursor_line_nr, bg = p.cursor_line, bold = true })
  hl('ColorColumn', { bg = p.surface })
  hl('SignColumn', { bg = p.bg })
  hl('LineNr', { fg = p.line_nr, bg = p.bg })
  hl('VertSplit', { fg = p.border, bg = 'NONE' })
  hl('WinSeparator', { fg = p.border, bg = 'NONE' })
  hl('StatusLine', { fg = p.fg, bg = p.surface })
  hl('StatusLineNC', { fg = p.muted, bg = p.bg })
  hl('TabLine', { fg = p.muted, bg = p.surface })
  hl('TabLineFill', { bg = p.bg })
  hl('TabLineSel', { fg = p.fg, bg = p.bg, bold = true })

  -- NeoTree — tool window matches editor bg. Selection uses a neutral "tool
  -- window" gray (like JetBrains element.selected), not the blue editor visual.
  local tool_select = p.tool_select or p.highlight
  local folder_icon = p.folder_icon or p.attribute or p.yellow
  hl('NeoTreeNormal',        { bg = p.bg, fg = p.fg })
  hl('NeoTreeNormalNC',      { bg = p.bg, fg = p.fg })
  hl('NeoTreeEndOfBuffer',   { bg = p.bg, fg = p.bg })
  hl('NeoTreeWinSeparator',  { bg = p.bg, fg = p.border })
  hl('NeoTreeCursorLine',    { bg = tool_select })
  hl('NeoTreeDirectoryName', { fg = p.fg })
  hl('NeoTreeDirectoryIcon', { fg = folder_icon })
  hl('NeoTreeFileName',      { fg = p.fg })
  hl('NeoTreeFileIcon',      { fg = p.muted })
  hl('NeoTreeRootName',      { fg = p.fg, bold = true })
  hl('NeoTreeExpander',      { fg = p.muted })
  hl('NeoTreeIndentMarker',  { fg = p.border })
  hl('NeoTreeFloatBorder',   { bg = p.surface, fg = p.border })
  hl('NeoTreeFloatTitle',    { bg = p.surface, fg = p.fg, bold = true })
  hl('NeoTreeTitleBar',      { bg = p.surface, fg = p.fg, bold = true })
  hl('NeoTreeModified',      { fg = p.orange })
  hl('NeoTreeGitAdded',      { fg = p.green })
  hl('NeoTreeGitModified',   { fg = p.blue })
  hl('NeoTreeGitDeleted',    { fg = p.red })
  hl('NeoTreeGitRenamed',    { fg = p.blue })
  hl('NeoTreeGitUntracked',  { fg = p.orange })
  hl('NeoTreeGitStaged',     { fg = p.green })
  hl('NeoTreeGitUnstaged',   { fg = p.yellow })
  hl('NeoTreeGitConflict',   { fg = p.red, bold = true })
  hl('NeoTreeGitIgnored',    { fg = p.muted })
  hl('NeoTreeDotfile',       { fg = p.muted })
  hl('NeoTreeHiddenByName',  { fg = p.muted })

  -- Syntax
  hl('Comment', { fg = p.comment, italic = true })
  hl('Keyword', { fg = p.orange, bold = true })
  hl('Conditional', { fg = p.orange, bold = true })
  hl('Repeat', { fg = p.orange, bold = true })
  hl('Statement', { fg = p.orange, bold = true })
  hl('StorageClass', { fg = p.orange, bold = true })
  hl('String', { fg = p.green })
  hl('Character', { fg = p.green })
  hl('Number', { fg = p.cyan })
  hl('Boolean', { fg = p.orange, bold = true })
  hl('Float', { fg = p.cyan })
  hl('Function', { fg = p.blue })
  hl('Identifier', { fg = p.fg })
  hl('Type', { fg = type_color })
  hl('Constant', { fg = p.purple, italic = true })
