-- =============================================================================
-- PUBLIC API
-- =============================================================================

-- Read the active palette name from the generated current-theme.lua.
-- Returns "intellij-dark" on first run / missing file.
local function read_current()
  local ok, mod = pcall(require, 'custom.current-theme')
  if ok and type(mod) == 'table' and mod.name then
    return mod.name
  end
  return 'intellij-dark'
end

-- Apply the palette with the given name (or the currently-recorded one).
M.apply = function(name)
  name = name or read_current()
  local palette = palettes[name] or palettes['intellij-dark']

  vim.o.background = palette.variant
  -- Pcall so we don't crash on first load before the colorscheme plugin exists.
  pcall(vim.cmd, 'colorscheme ' .. palette.colorscheme)
  apply_highlights(palette)

  -- Tell lualine (and anyone else listening) to refresh with new colors.
  pcall(function()
    require('lualine').setup { options = { theme = M.lualine_theme() } }
  end)
end

-- Return the active palette table (loads the current one if nothing specified).
M.palette = function(name)
  return palettes[name or read_current()] or palettes['intellij-dark']
end

-- Build a lualine theme from the active palette. Flat, IntelliJ-style:
-- bar bg = surface, mode letter colored by mode.
M.lualine_theme = function()
  local p = M.palette()
  local mode = function(accent)
    return {
      a = { bg = p.surface, fg = accent, gui = 'bold' },
      b = { bg = p.surface, fg = p.fg },
      c = { bg = p.surface, fg = p.muted },
    }
  end
  return {
    normal = mode(p.blue),
    insert = mode(p.green),
    visual = mode(p.purple),
    replace = mode(p.red),
    command = mode(p.orange),
    inactive = {
      a = { bg = p.surface, fg = p.muted },
      b = { bg = p.surface, fg = p.muted },
      c = { bg = p.surface, fg = p.muted },
    },
  }
end

-- Reload current palette after switch-theme rewrote current-theme.lua.
M.reload = function()
  package.loaded['custom.current-theme'] = nil
  M.apply()
end

-- Cycle to the next palette by shelling out to switch-theme, which updates
-- every tool — then reload inside this nvim instance.
M.toggle_theme = function()
  vim.fn.system { vim.fn.expand('~/Projects/Sandbox/dotfiles/scripts/switch-theme.sh'), 'next' }
  M.reload()
end

M.setup = function()
  M.apply()
  vim.keymap.set('n', '<leader>xt', M.toggle_theme, { desc = 'Cycle [T]heme palette' })
end

return M
